import React, { useState } from "react";
import { useAuth } from "../../contexts/AuthContext";
import "./LoginPage.css";

// onSuccess is optional — used when LoginPage is rendered as a full-screen gate
// (not inside RuntimeTab). When provided, it is called after a successful login
// so the parent can transition screens. When omitted (RuntimeTab usage), the
// AuthContext user state update alone causes the parent to re-render correctly.
export default function LoginPage({ onSuccess } = {}) {
  const { login }   = useAuth();
  const [pw,  setPw]     = useState("");
  const [err, setErr]    = useState("");
  const [busy, setBusy]  = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!pw.trim() || busy) return;
    setBusy(true);
    setErr("");
    const result = await login(pw);
    if (!result.success) {
      setErr(result.error || "Invalid password");
    } else {
      onSuccess?.();
    }
    setBusy(false);
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">J</div>
        <h1 className="login-title">Sign in to Jarvis</h1>
        <p className="login-subtitle">Enter your password to continue</p>
        <form className="login-form" onSubmit={handleSubmit}>
          <input
            type="password"
            className="login-input"
            placeholder="Operator password"
            value={pw}
            onChange={e => setPw(e.target.value)}
            autoFocus
            disabled={busy}
            autoComplete="current-password"
          />
          {err && <p className="login-error">{err}</p>}
          <button
            type="submit"
            className="login-btn"
            disabled={busy || !pw.trim()}
          >
            {busy ? "Authenticating…" : "Sign in"}
          </button>
        </form>
      </div>
    </div>
  );
}
